<script setup lang="ts">
import { useActivityStore } from '../../stores/activityStore'
import { useAppStore } from '../../stores/appStore'
const activity = useActivityStore(); const app = useAppStore()
function create() { const name = prompt('Playlist name')?.trim(); if (!name) return; activity.createPlaylist(name); app.toast('Playlist saved in this browser', 'success') }
</script>
<template><section class="page-stack"><div class="page-actions"><div><span class="eyebrow">Local collections</span><h1 class="page-title">Playlists</h1><p class="page-description">The backend has no playlist endpoint, so these collections are clearly stored in this browser.</p></div><button class="btn btn-primary" :disabled="!activity.queue.length" :title="!activity.queue.length ? 'Add media to Queue before creating a playlist' : undefined" @click="create">Save queue as playlist</button></div><div v-if="!activity.playlists.length" class="friendly-empty"><strong>No local playlists</strong><p>Add media to Queue, then save it here. No server feature is being silently faked.</p><button class="btn btn-secondary" style="margin-top:14px" @click="app.setSection('queue')">Open Queue</button></div><article v-for="playlist in activity.playlists" :key="playlist.id" class="card" style="display:flex;gap:14px;align-items:center"><span class="kind-mark">LIST</span><div style="flex:1"><strong>{{ playlist.name }}</strong><div class="path-text">{{ playlist.items.length }} items · stored locally</div></div><button class="btn btn-danger btn-sm" @click="activity.removePlaylist(playlist.id)">Delete</button></article></section></template>
